def search_hadith_by_substring(substring, max_results=50):
    res=[]
    ns=normalize_ar(substring)
    for rec in hadith_data:
        for field in ('hadithTxt','Matn'):
            txt=rec.get(field) or ''
            if not txt:
                continue
            nt=normalize_ar(txt)
            if ns in nt:
                res.append((rec['hadithID'], field, txt))
                break
        if len(res)>=max_results:
            break
    return res

